 518→    setSelectedIndex(0);
 519→    setActionsOpen(false);
 520→  }, []);
 521→
 522→  const handleFilterChange = useCallback((value: string) => {
 523→    setFilterValue(value);
 524→    setSelectedIndex(0);
 525→  }, []);
