 681→              <Kbd
 682→                keys={[
 683→                  '⌘',
 684→                  'N',
 685→                ]}
 686→              />
 687→            ),
 688→            onClick: handleOpenCreateSnippet,
 689→          },
 690→        ],
 691→      },
 692→      {
