  1→import {
  2→  createContext,
  3→  useCallback,
  4→  useContext,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→
 10→export interface BreadcrumbItem {
 11→  label: string;
 12→  onBack?: () => void;
 13→}
 14→
 15→export interface NavigationEntry<T = unknown> {
 16→  title: string;
 17→  data: T;
 18→}
 19→
 20→export type TransitionDirection = 'push' | 'pop' | 'none';
 21→
 22→interface NavigationState<T> {
 23→  stack: NavigationEntry<T>[];
 24→  direction: TransitionDirection;
 25→  counter: number;
 26→}
 27→
 28→export interface NavigationContext<T = unknown> {
 29→  push: (title: string, data: T) => void;
 30→  pop: () => void;
 31→  popToRoot: () => void;
 32→  currentEntry: NavigationEntry<T> | null;
 33→  breadcrumbs: BreadcrumbItem[];
 34→  canGoBack: boolean;
 35→  direction: TransitionDirection;
 36→  stackDepth: number;
 37→  navKey: number;
 38→}
 39→
 40→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 41→const NavContext = createContext<NavigationContext<any> | null>(null);
 42→
 43→export const NavigationContextProvider = NavContext.Provider;
 44→
 45→export function useNavigation<T = unknown>(): NavigationContext<T> {
 46→  const ctx = useContext(NavContext);
 47→  if (!ctx) {
 48→    throw new Error('useNavigation must be used within a NavigationProvider');
 49→  }
 50→  return ctx as NavigationContext<T>;
 51→}
 52→
 53→export function useNavigationStack<T = unknown>(
 54→  rootTitle: string,
 55→): NavigationContext<T> {
 56→  const [state, setState] = useState<NavigationState<T>>({
 57→    stack: [],
 58→    direction: 'none',
 59→    counter: 0,
 60→  });
 61→
 62→  const counterRef = useRef(0);
 63→
 64→  const push = useCallback((title: string, data: T) => {
 65→    counterRef.current += 1;
 66→    const nextCounter = counterRef.current;
 67→    setState(prev => ({
 68→      stack: [
 69→        ...prev.stack,
 70→        {
 71→          title,
 72→          data,
 73→        },
 74→      ],
 75→      direction: 'push',
 76→      counter: nextCounter,
 77→    }));
 78→  }, []);
 79→
 80→  const pop = useCallback(() => {
 81→    counterRef.current += 1;
 82→    const nextCounter = counterRef.current;
 83→    setState(prev => {
 84→      if (prev.stack.length === 0) return prev;
 85→      return {
 86→        stack: prev.stack.slice(0, -1),
 87→        direction: 'pop',
 88→        counter: nextCounter,
 89→      };
 90→    });
 91→  }, []);
 92→
 93→  const popToRoot = useCallback(() => {
 94→    counterRef.current += 1;
 95→    const nextCounter = counterRef.current;
 96→    setState(prev => {
 97→      if (prev.stack.length === 0) return prev;
 98→      return {
 99→        stack: [],
100→        direction: 'pop',
101→        counter: nextCounter,
102→      };
103→    });
104→  }, []);
105→
106→  const currentEntry: NavigationEntry<T> | null =
107→    state.stack.length > 0 ? state.stack[state.stack.length - 1]! : null;
108→
109→  const canGoBack = state.stack.length > 0;
110→
111→  const breadcrumbs = useMemo(() => {
112→    if (state.stack.length === 0) return [];
113→
114→    const crumbs: BreadcrumbItem[] = [
115→      {
116→        label: rootTitle,
117→        onBack: () => {
118→          counterRef.current += 1;
119→          const nextCounter = counterRef.current;
120→          setState(() => ({
121→            stack: [],
122→            direction: 'pop' as const,
123→            counter: nextCounter,
124→          }));
125→        },
126→      },
127→    ];
128→
129→    for (let i = 0; i < state.stack.length; i++) {
130→      const entry = state.stack[i]!;
131→      const isLast = i === state.stack.length - 1;
132→      if (isLast) {
133→        crumbs.push({ label: entry.title });
134→      } else {
135→        const targetDepth = i + 1;
136→        crumbs.push({
137→          label: entry.title,
138→          onBack: () => {
139→            counterRef.current += 1;
140→            const nextCounter = counterRef.current;
141→            setState(prev => ({
142→              stack: prev.stack.slice(0, targetDepth),
143→              direction: 'pop' as const,
144→              counter: nextCounter,
145→            }));
146→          },
147→        });
148→      }
149→    }
150→
151→    return crumbs;
152→  }, [
153→    state.stack,
154→    rootTitle,
155→  ]);
156→
157→  return useMemo(
158→    () => ({
159→      push,
160→      pop,
161→      popToRoot,
162→      currentEntry,
163→      breadcrumbs,
164→      canGoBack,
165→      direction: state.direction,
166→      stackDepth: state.stack.length,
167→      navKey: state.counter,
168→    }),
169→    [
170→      push,
171→      pop,
172→      popToRoot,
173→      currentEntry,
174→      breadcrumbs,
175→      canGoBack,
176→      state.direction,
177→      state.stack.length,
178→      state.counter,
179→    ],
180→  );
181→}
