 11→
 12→export interface FormTagPickerOption {
 13→  label: string;
 14→  value: string;
 15→}
 16→
 17→interface FormTagPickerProps {
 18→  label: string;
 19→  value: string[];
 20→  onChange: (value: string[]) => void;
 21→  options: FormTagPickerOption[];
 22→  placeholder?: string;
 23→  description?: string;
 24→  error?: string;
 25→  autoFocus?: boolean;
