 27→
 28→export function FormTagPicker({
 29→  label,
 30→  value,
 31→  onChange,
 32→  options,
 33→  placeholder,
 34→  description,
 35→  error,
 36→  autoFocus,
 37→}: FormTagPickerProps) {
 38→  const id = useId();
 39→  const listboxId = useId();
 40→  const [query, setQuery] = useState('');
 41→  const [open, setOpen] = useState(false);
 42→  const [activeIndex, setActiveIndex] = useState(0);
 43→  const inputRef = useRef<HTMLInputElement>(null);
 44→  const containerRef = useRef<HTMLDivElement>(null);
 45→  const menuRef = useRef<HTMLUListElement>(null);
 46→
 47→  const optionLabelMap = useMemo(
 48→    () =>
 49→      new Map(
 50→        options.map(o => [
 51→          o.value,
 52→          o.label,
 53→        ]),
 54→      ),
 55→    [options],
 56→  );
 57→
 58→  const availableOptions = useMemo(
 59→    () =>
 60→      options.filter(
 61→        opt =>
 62→          !value.includes(opt.value) &&
 63→          opt.label.toLowerCase().includes(query.toLowerCase()),
 64→      ),
 65→    [
 66→      options,
 67→      value,
 68→      query,
 69→    ],
 70→  );
 71→
 72→  const resetDropdown = useCallback(() => {
 73→    setOpen(false);
 74→    setQuery('');
 75→    setActiveIndex(0);
 76→  }, []);
 77→
 78→  useEffect(() => {
 79→    setActiveIndex(0);
 80→  }, [query]);
 81→
 82→  useEffect(() => {
 83→    if (!open) return;
 84→    const activeEl = menuRef.current?.querySelector('[data-active="true"]');
 85→    if (activeEl) {
 86→      activeEl.scrollIntoView({ block: 'nearest' });
 87→    }
 88→  }, [
 89→    activeIndex,
 90→    open,
 91→  ]);
 92→
 93→  useEffect(() => {
 94→    function handleClickOutside(e: MouseEvent) {
 95→      if (
 96→        containerRef.current &&
 97→        !containerRef.current.contains(e.target as Node)
 98→      ) {
 99→        resetDropdown();
100→      }
101→    }
102→    if (open) {
103→      document.addEventListener('mousedown', handleClickOutside);
104→    }
105→    return () => document.removeEventListener('mousedown', handleClickOutside);
106→  }, [
107→    open,
108→    resetDropdown,
109→  ]);
110→
111→  const selectOption = useCallback(
112→    (optionValue: string) => {
113→      onChange([
114→        ...value,
115→        optionValue,
116→      ]);
117→      setQuery('');
118→      setActiveIndex(0);
119→      inputRef.current?.focus();
120→    },
121→    [
122→      value,
123→      onChange,
124→    ],
125→  );
126→
127→  const removeTag = useCallback(
128→    (optionValue: string) => {
129→      onChange(value.filter(v => v !== optionValue));
130→      inputRef.current?.focus();
131→    },
132→    [
133→      value,
134→      onChange,
135→    ],
136→  );
137→
138→  const handleKeyDown = useCallback(
139→    (e: React.KeyboardEvent) => {
140→      if (e.key === 'Backspace' && !query && value.length > 0) {
141→        onChange(value.slice(0, -1));
142→        return;
143→      }
144→
145→      if (!open || availableOptions.length === 0) {
146→        if (e.key === 'ArrowDown' && !open && availableOptions.length > 0) {
147→          e.preventDefault();
148→          setOpen(true);
149→        }
150→        return;
151→      }
152→
153→      switch (e.key) {
154→        case 'ArrowDown':
155→          e.preventDefault();
156→          setActiveIndex(prev =>
157→            prev < availableOptions.length - 1 ? prev + 1 : 0);
158→          break;
159→        case 'ArrowUp':
160→          e.preventDefault();
161→          setActiveIndex(prev =>
162→            prev > 0 ? prev - 1 : availableOptions.length - 1);
163→          break;
164→        case 'Enter':
165→          e.preventDefault();
166→          e.stopPropagation();
167→          if (availableOptions[activeIndex]) {
168→            selectOption(availableOptions[activeIndex].value);
169→          }
170→          break;
171→        case 'Escape':
172→          e.preventDefault();
173→          e.stopPropagation();
174→          resetDropdown();
175→          break;
176→        case 'Tab':
177→          resetDropdown();
178→          break;
179→      }
180→    },
181→    [
182→      open,
183→      query,
184→      value,
185→      onChange,
186→      availableOptions,
187→      activeIndex,
188→      selectOption,
189→      resetDropdown,
190→    ],
191→  );
192→
193→  const handleInputChange = useCallback(
194→    (e: React.ChangeEvent<HTMLInputElement>) => {
195→      setQuery(e.target.value);
196→      if (!open) {
197→        setOpen(true);
198→      }
199→    },
200→    [open],
201→  );
202→
203→  const handleInputFocus = useCallback(() => {
204→    if (availableOptions.length > 0) {
205→      setOpen(true);
206→    }
207→  }, [availableOptions.length]);
208→
209→  const getLabel = useCallback(
210→    (optionValue: string) => optionLabelMap.get(optionValue) ?? optionValue,
211→    [optionLabelMap],
212→  );
213→
214→  const activeOption = availableOptions[activeIndex];
215→  const activeOptionId =
216→    open && activeOption
217→      ? `${listboxId}-option-${activeOption.value}`
218→      : undefined;
219→
220→  return (
221→    <FormField
222→      label={label}
223→      description={description}
224→      error={error}
225→      htmlFor={id}
226→    >
227→      <div className="form-tag-picker" ref={containerRef}>
228→        <div
229→          className="form-tag-picker__input-area"
230→          onClick={() => inputRef.current?.focus()}
231→        >
232→          {value.map(v => (
233→            <span key={v} className="form-tag-picker__tag">
234→              <span className="form-tag-picker__tag-label">{getLabel(v)}</span>
235→              <button
236→                type="button"
237→                className="form-tag-picker__tag-remove"
238→                onClick={e => {
239→                  e.stopPropagation();
240→                  removeTag(v);
241→                }}
242→                aria-label={`Remove ${getLabel(v)}`}
243→              >
244→                <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
245→                  <path
246→                    d="M1 1L7 7M7 1L1 7"
247→                    stroke="currentColor"
248→                    strokeWidth="1.5"
249→                    strokeLinecap="round"
250→                  />
251→                </svg>
252→              </button>
253→            </span>
254→          ))}
255→          <input
256→            id={id}
257→            ref={inputRef}
258→            className="form-tag-picker__input"
259→            type="text"
260→            value={query}
261→            onChange={handleInputChange}
262→            onFocus={handleInputFocus}
263→            onKeyDown={handleKeyDown}
264→            placeholder={value.length === 0 ? placeholder : undefined}
265→            autoFocus={autoFocus}
266→            spellCheck={false}
267→            autoComplete="off"
268→            role="combobox"
269→            aria-expanded={open}
270→            aria-controls={open ? listboxId : undefined}
271→            aria-activedescendant={activeOptionId}
272→            aria-invalid={error ? true : undefined}
273→            aria-describedby={error ? `${id}-error` : undefined}
274→          />
275→        </div>
276→        {open && availableOptions.length > 0 && (
277→          <ul
278→            id={listboxId}
279→            ref={menuRef}
280→            className="form-tag-picker__menu"
281→            role="listbox"
282→            aria-label={label}
283→          >
284→            {availableOptions.map((opt, i) => (
285→              <li
286→                key={opt.value}
287→                id={`${listboxId}-option-${opt.value}`}
288→                className={`form-tag-picker__option${i === activeIndex ? ' form-tag-picker__option--active' : ''}`}
289→                role="option"
290→                aria-selected={i === activeIndex}
291→                data-active={i === activeIndex}
292→                onMouseEnter={() => setActiveIndex(i)}
293→                onMouseDown={e => {
294→                  e.preventDefault();
295→                  selectOption(opt.value);
296→                }}
297→              >
298→                {opt.label}
299→              </li>
300→            ))}
301→          </ul>
302→        )}
303→      </div>
304→    </FormField>
305→  );
306→}
