  5→export interface FilePickerFile {
  6→  name: string;
  7→  size: number;
  8→  type: string;
  9→}
 10→
 11→interface FormFilePickerProps {
 12→  label: string;
 13→  value: FilePickerFile[];
 14→  onChange: (files: FilePickerFile[]) => void;
 15→  allowMultiple?: boolean;
 16→  accept?: string;
 17→  description?: string;
 18→  error?: string;
 19→}
 20→
 21→function formatFileSize(bytes: number): string {
 22→  if (bytes < 1024) return `${bytes} B`;
 23→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
 24→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
 25→}
 26→
 27→function fileKey(file: FilePickerFile): string {
 28→  return `${file.name}:${file.size}:${file.type}`;
 29→}
 30→
 31→export function FormFilePicker({
 32→  label,
 33→  value,
 34→  onChange,
 35→  allowMultiple = false,
 36→  accept,
 37→  description,
 38→  error,
 39→}: FormFilePickerProps) {
 40→  const id = useId();
 41→  const inputRef = useRef<HTMLInputElement>(null);
 42→
 43→  const handleChange = useCallback(
 44→    (e: React.ChangeEvent<HTMLInputElement>) => {
 45→      const fileList = e.target.files;
 46→      if (!fileList || fileList.length === 0) return;
 47→
 48→      const picked: FilePickerFile[] = Array.from(fileList).map(f => ({
 49→        name: f.name,
 50→        size: f.size,
 51→        type: f.type,
 52→      }));
 53→
 54→      if (allowMultiple) {
 55→        const existingKeys = new Set(value.map(fileKey));
 56→        const deduped = picked.filter(f => !existingKeys.has(fileKey(f)));
 57→        onChange([
 58→          ...value,
 59→          ...deduped,
 60→        ]);
 61→      } else {
 62→        onChange(picked.slice(0, 1));
 63→      }
 64→
 65→      e.target.value = '';
 66→    },
 67→    [
 68→      value,
 69→      onChange,
 70→      allowMultiple,
 71→    ],
 72→  );
 73→
 74→  const removeFile = useCallback(
 75→    (index: number) => {
 76→      onChange(value.filter((_, i) => i !== index));
 77→    },
 78→    [
 79→      value,
 80→      onChange,
 81→    ],
 82→  );
 83→
 84→  const handleBrowseClick = useCallback(() => {
 85→    inputRef.current?.click();
 86→  }, []);
 87→
 88→  return (
 89→    <FormField
 90→      label={label}
 91→      description={description}
 92→      error={error}
 93→      htmlFor={id}
 94→    >
 95→      <div className="form-file-picker">
 96→        <input
 97→          id={id}
 98→          ref={inputRef}
 99→          className="form-file-picker__native-input"
100→          type="file"
101→          multiple={allowMultiple}
102→          accept={accept}
103→          onChange={handleChange}
104→          aria-invalid={error ? true : undefined}
105→          aria-describedby={error ? `${id}-error` : undefined}
106→          tabIndex={-1}
107→        />
108→        {value.length > 0 && (
109→          <div
110→            className="form-file-picker__files"
111→            role="list"
112→            aria-label="Selected files"
113→          >
114→            {value.map((file, i) => (
115→              <span
116→                key={fileKey(file)}
117→                className="form-file-picker__pill"
118→                role="listitem"
119→              >
120→                <svg
121→                  className="form-file-picker__pill-icon"
122→                  width="12"
123→                  height="12"
124→                  viewBox="0 0 16 16"
125→                  fill="none"
126→                >
127→                  <path
128→                    d="M4 1.5h5.586a1 1 0 0 1 .707.293l2.414 2.414a1 1 0 0 1 .293.707V13.5a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1v-11a1 1 0 0 1 1-1Z"
129→                    stroke="currentColor"
130→                    strokeWidth="1.25"
131→                  />
132→                  <path
133→                    d="M9.5 1.5V4a.5.5 0 0 0 .5.5h2.5"
134→                    stroke="currentColor"
135→                    strokeWidth="1.25"
136→                    strokeLinecap="round"
137→                    strokeLinejoin="round"
138→                  />
139→                </svg>
140→                <span className="form-file-picker__pill-name">{file.name}</span>
141→                <span className="form-file-picker__pill-size">
142→                  {formatFileSize(file.size)}
143→                </span>
144→                <button
145→                  type="button"
146→                  className="form-file-picker__pill-remove"
147→                  onClick={() => removeFile(i)}
148→                  aria-label={`Remove ${file.name}`}
149→                >
150→                  <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
151→                    <path
152→                      d="M1 1L7 7M7 1L1 7"
153→                      stroke="currentColor"
154→                      strokeWidth="1.5"
155→                      strokeLinecap="round"
156→                    />
157→                  </svg>
158→                </button>
159→              </span>
160→            ))}
161→          </div>
162→        )}
163→        <button
164→          type="button"
165→          className="form-file-picker__browse"
166→          onClick={handleBrowseClick}
167→        >
168→          <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
169→            <path
170→              d="M8 3v10M3 8h10"
171→              stroke="currentColor"
172→              strokeWidth="1.5"
173→              strokeLinecap="round"
174→            />
175→          </svg>
176→          {value.length === 0
177→            ? 'Choose File'
178→            : allowMultiple
179→              ? 'Add More'
180→              : 'Replace File'}
181→        </button>
182→      </div>
183→    </FormField>
184→  );
185→}
