 97→    function handleKeyDown(e: KeyboardEvent) {
 98→      if (e.key === 'Escape' || e.key === 'Tab') {
 99→        e.preventDefault();
100→        e.stopPropagation();
101→        setOpen(false);
102→        triggerRef.current?.focus();
103→        return;
104→      }
105→
106→      if (e.key === 'ArrowDown') {
107→        e.preventDefault();
108→        e.stopPropagation();
109→        setActiveIndex(i => (i < flatOptions.length - 1 ? i + 1 : 0));
110→        return;
111→      }
112→
113→      if (e.key === 'ArrowUp') {
114→        e.preventDefault();
115→        e.stopPropagation();
116→        setActiveIndex(i => (i > 0 ? i - 1 : flatOptions.length - 1));
117→        return;
118→      }
119→
120→      if (e.key === 'Enter') {
121→        e.preventDefault();
122→        e.stopPropagation();
123→        selectOption(activeIndex);
124→      }
125→    }
